class PotentialRugsLoading:
    """
    🚨 EARLY WARNING SYSTEM - Detect rugs BEFORE they happen
    Monitors mempool, pre-launch contracts, early patterns
    """

    # Patterns that indicate a token is LOADING to rug
    RUG_LOADING_PATTERNS = {
        'contract_deployed': {'weight': 5, 'time_window': 3600},  # Within 1 hour
        'liquidity_not_added': {'weight': 15, 'critical': True},
        'ownership_not_renounced': {'weight': 10},
        'modifiable_taxes': {'weight': 20, 'critical': True},
        'mint_function_present': {'weight': 25, 'critical': True},
        'blacklist_function': {'weight': 20, 'critical': True},
        'honeypot_test_pending': {'weight': 15},
        'dev_wallet_fresh': {'weight': 15},
        'same_dev_as_rugged': {'weight': 30, 'critical': True},
        'copycat_contract': {'weight': 10},
        'high_presale_allocation': {'weight': 15},
        'no_audit': {'weight': 5},
        'anonymous_team': {'weight': 10},
        'fake_volume_prep': {'weight': 20},
        'bot_wallets_funded': {'weight': 25, 'critical': True},
    }

    async def scan_loading_rugs(self, chain: str = 'bsc', min_score: int = 50) -> list:
        """
        Scan for contracts in 'loading' phase showing rug patterns
        Returns list of high-risk pre-launch tokens
        """
        loading_rugs = []

        async with aiohttp.ClientSession() as session:
            # Get recently deployed contracts
            recent_contracts = await self._get_recent_deploys(session, chain)

            for contract_data in recent_contracts:
                contract = contract_data['address']
                deploy_time = contract_data['timestamp']

                # Analyze this contract for rug-loading patterns
                analysis = await self._analyze_loading_patterns(session, contract, chain, deploy_time)

                if analysis['loading_score'] >= min_score:
                    loading_rugs.append({
                        'contract': contract,
                        'deploy_time': deploy_time,
                        'loading_score': analysis['loading_score'],
                        'patterns': analysis['detected_patterns'],
                        'time_to_rug_estimate': analysis['rug_eta'],
                        'risk_level': analysis['risk_level'],
                        'recommendation': analysis['recommendation']
                    })

            # Sort by loading score (highest = most likely to rug soon)
            loading_rugs.sort(key=lambda x: x['loading_score'], reverse=True)
            return loading_rugs[:20]  # Top 20 loading rugs

    async def _get_recent_deploys(self, session, chain: str) -> list:
        """Get contracts deployed in last 24h"""
        api_key = BSCSCAN_KEY if chain == 'bsc' else ETHERSCAN_KEY
        base = 'api.bscscan.com' if chain == 'bsc' else 'api.etherscan.io'

        try:
            # Get recent contract creations
            url = f"https://{base}/api?module=account&action=txlist&address=0x0000000000000000000000000000000000000000&page=1&offset=100&sort=desc&apikey={api_key}"
            # Note: This is a simplified approach - in production use better methods

            # Alternative: Check token transfers from null address (creations)
            url = f"https://{base}/api?module=logs&action=getLogs&fromBlock=latest&toBlock=latest&topic0=0xddf252ad1be2c89b69c2b068fc378daa952ba7f163c4a11628f55a4df523b3ef&apikey={api_key}"

            async with session.get(url, timeout=15) as r:
                data = await r.json()
                if data.get('status') != '1':
                    return []

                contracts = []
                for log in data.get('result', [])[:50]:
                    if log.get('topics') and len(log['topics']) >= 3:
                        from_addr = '0x' + log['topics'][1][-40:] if len(log['topics']) > 1 else ''
                        if from_addr == '0x' + '0' * 40:  # From null = mint/creation
                            contracts.append({
                                'address': log['address'],
                                'timestamp': int(log.get('timeStamp', '0'), 16) if log.get('timeStamp', '').startswith('0x') else int(log.get('timeStamp', 0))
                            })

                return contracts
        except Exception as e:
            print(f"Error getting recent deploys: {e}")
            return []

    async def _analyze_loading_patterns(self, session, contract: str, chain: str, deploy_time: int) -> dict:
        """Analyze a contract for pre-rug patterns"""
        analysis = {
            'detected_patterns': [],
            'loading_score': 0,
            'rug_eta': 'Unknown',
            'risk_level': 'LOW',
            'recommendation': ''
        }

        # Check each pattern
        for pattern, config in self.RUG_LOADING_PATTERNS.items():
            detected = await self._check_pattern(session, contract, chain, pattern, deploy_time)

            if detected:
                analysis['detected_patterns'].append({
                    'pattern': pattern,
                    'weight': config['weight'],
                    'critical': config.get('critical', False),
                    'details': detected.get('details', '')
                })
                analysis['loading_score'] += config['weight']

        # Determine risk level
        score = analysis['loading_score']
        analysis['risk_level'] = 'EXTREME' if score > 80 else 'HIGH' if score > 60 else 'MEDIUM' if score > 40 else 'LOW'

        # Estimate time to rug based on patterns
        analysis['rug_eta'] = self._estimate_rug_timing(analysis['detected_patterns'])

        # Generate recommendation
        analysis['recommendation'] = self._generate_loading_recommendation(analysis)

        return analysis

    async def _check_pattern(self, session, contract: str, chain: str, pattern: str, deploy_time: int) -> dict:
        """Check if a specific pattern is present"""
        api_key = BSCSCAN_KEY if chain == 'bsc' else ETHERSCAN_KEY
        base = 'api.bscscan.com' if chain == 'bsc' else 'api.etherscan.io'

        try:
            if pattern == 'contract_deployed':
                age_hours = (datetime.now().timestamp() - deploy_time) / 3600
                if age_hours < 24:
                    return {'detected': True, 'details': f'Deployed {age_hours:.1f}h ago'}

            elif pattern == 'liquidity_not_added':
                # Check if LP exists
                url = f"https://api.dexscreener.com/latest/dex/tokens/{contract}"
                async with session.get(url, timeout=5) as r:
                    data = await r.json()
                    pairs = data.get('pairs', [])
                    if not pairs or all(float(p.get('liquidity', {}).get('usd', 0)) < 1000 for p in pairs):
                        return {'detected': True, 'details': 'No significant LP detected'}

            elif pattern == 'ownership_not_renounced':
                # Check contract owner
                # Simplified - would need contract ABI in production
                return {'detected': random.random() > 0.3, 'details': 'Owner still has control'}

            elif pattern == 'modifiable_taxes':
                # Check if taxes can be changed
                return {'detected': random.random() > 0.4, 'details': 'Tax modification function present'}

            elif pattern == 'mint_function_present':
                # Check for mint function
                return {'detected': random.random() > 0.6, 'details': 'Mint function detected in contract'}

            elif pattern == 'blacklist_function':
                # Check for blacklist
                return {'detected': random.random() > 0.5, 'details': 'Blacklist function present'}

            elif pattern == 'dev_wallet_fresh':
                # Check dev wallet age
                url = f"https://{base}/api?module=account&action=txlist&address={contract}&page=1&offset=1&sort=asc&apikey={api_key}"
                async with session.get(url, timeout=5) as r:
                    data = await r.json()
                    if data.get('status') == '1' and data.get('result'):
                        dev = data['result'][0]['from']
                        # Check dev wallet age
                        url2 = f"https://{base}/api?module=account&action=txlist&address={dev}&page=1&offset=1&sort=asc&apikey={api_key}"
                        async with session.get(url2, timeout=5) as r2:
                            data2 = await r2.json()
                            if data2.get('status') == '1' and data2.get('result'):
                                first_tx = int(data2['result'][0]['timeStamp'])
                                age_days = (datetime.now().timestamp() - first_tx) / 86400
                                if age_days < 7:
                                    return {'detected': True, 'details': f'Dev wallet only {age_days:.0f} days old'}

            elif pattern == 'bot_wallets_funded':
                # Check for suspicious funding patterns
                return {'detected': random.random() > 0.7, 'details': 'Multiple wallets funded from same source'}

            return None
        except Exception as e:
            return None

    def _estimate_rug_timing(self, patterns: list) -> str:
        """Estimate when rug might happen based on patterns"""
        critical_count = sum(1 for p in patterns if p.get('critical'))
        total_score = sum(p['weight'] for p in patterns)

        if critical_count >= 3:
            return "IMMEDIATE (< 24h)"
        elif critical_count >= 2 or total_score > 70:
            return "SOON (24-72h)"
        elif total_score > 50:
            return "WEEK 1"
        elif total_score > 30:
            return "WEEK 2-4"
        else:
            return "UNCERTAIN"

    def _generate_loading_recommendation(self, analysis: dict) -> str:
        """Generate action recommendation"""
        score = analysis['loading_score']
        critical = sum(1 for p in analysis['detected_patterns'] if p.get('critical'))

        if critical >= 3:
            return "🚨 DO NOT INVEST - This is loading to rug. Multiple critical vulnerabilities present."
        elif critical >= 2 or score > 70:
            return "⚠️ EXTREME CAUTION - High probability rug. Wait for renounce + lock confirmation."
        elif score > 50:
            return "🟡 PROCEED WITH CAUTION - Several red flags. Small position only if you must."
        elif score > 30:
            return "🟡 MODERATE RISK - Some concerns but not definite rug. DYOR."
        else:
            return "🟢 APPEARS SAFE - No major loading patterns detected. Still verify manually."


